const rows = $input.all();
const today = new Date();
today.setHours(0, 0, 0, 0);

const items = rows.map(row => {
  const dueDate = new Date(row.json.due_date);
  const diffMs = today.getTime() - dueDate.getTime();
  const daysOverdue = Math.max(0, Math.floor(diffMs / (1000 * 60 * 60 * 24)));

  return {
    customerName: row.json.customer_name || '',
    customerAddress: row.json.customer_address || '',
    invoiceNumber: row.json.invoice_number || '',
    amountDue: String(row.json.amount_due || '0.00'),
    dueDate: row.json.due_date || '',
    daysOverdue: String(daysOverdue),
    companyName: row.json.company_name || ''
  };
});

return [{ json: { documentId: 'YOUR_DOCUMENT_ID', items: JSON.stringify(items) } }];

